const ws = new WebSocket('ws://localhost:8765');

ws.onopen = () => {
    // List devices
    ws.send(JSON.stringify({action: 'list_devices'}));
};

ws.onmessage = (event) => {
    const data = JSON.parse(event.data);
    console.log('Received:', data);

    if (data.devices) {
        data.devices.forEach(device => {
            console.log(`Device: ${device.name}, Paired: ${device.paired}`);
        });
    }
};

// Get battery for specific device
function getBattery(deviceId) {
    ws.send(JSON.stringify({action: 'get_battery', device_id: deviceId}));
}
